import { Mistral } from '@mistralai/mistralai';
import dotenv from 'dotenv';

dotenv.config();

const client = new Mistral({
  apiKey: process.env.MISTRAL_API_KEY,
});

const messages = [
    {
      "role": "user",
      "content": "Hello!"
    }
  ];

const completionArgs = {
  temperature: 0.7,
  maxTokens: 2048,
  topP: 1
};

const tools = [];

async function main() {
  const response = await client.beta.conversations.start({
    inputs: messages,
    model: 'mistral-medium-latest',
    instructions: ``,
    ...completionArgs,
    tools
  });
  console.log(response);
}

main();

imageMessage.caption:
🚨🚨🚨

Pour un *grid* 5x5 en *CSS*, avec des éléments occupant différentes tailles sans position fixe 🤩, utiliser le mode *"dense"* pour la propriété *grid-auto-flow* permet de "remplir les trous" créés par les éléments précédents, en poussant les éléments suivants qui s'y adaptent 🖼. Cela peut être utile pour des choses comme une galerie d'images avec des tailles aléatoires 📁.

Exemple de code :
.grid {
  **grid-template-rows**: repeat(5, 10rem);
  **grid-template-columns**: repeat(5, 10rem);
}

.item-2 {
  **grid-row-end**: span 2;
  **grid-column-end**: span 2;
}
